//! CLI subprocess tests for `vc-x1 sync`.
//!
//! Drives the installed-binary surface end-to-end: a bare git
//! remote plus two independent `jj git clone`s (the "two machines"
//! shape). Clone A commits and pushes; `vc-x1 sync --no-check -R
//! <clone-b>` must fast-forward clone B's `main` to the pushed
//! head and reposition `@` onto it.

mod common;

use std::fs;
use std::path::{Path, PathBuf};
use std::process::Command;

use common::{CliFixture, run_ok};

/// Run `jj <args>` in `dir` and assert success; returns trimmed stdout.
fn jj(dir: &Path, args: &[&str]) -> String {
    let out = Command::new("jj")
        .args(args)
        .current_dir(dir)
        .output()
        .expect("spawn jj");
    assert!(
        out.status.success(),
        "jj {args:?} failed in {}: {}",
        dir.display(),
        String::from_utf8_lossy(&out.stderr)
    );
    String::from_utf8_lossy(&out.stdout).trim().to_string()
}

/// Resolve `rev` to its short commit id in `repo`.
fn cid(repo: &Path, rev: &str) -> String {
    jj(
        repo,
        &["log", "-r", rev, "--no-graph", "-T", "commit_id.short(12)"],
    )
}

/// Write a minimal jj user config under the fixture's isolated HOME
/// so jj invocations spawned *inside* `vc-x1` (which inherits the
/// overridden `HOME`) have an identity.
fn write_jj_config(home: &Path) {
    let dir = home.join(".config/jj");
    fs::create_dir_all(&dir).expect("mkdir jj config dir");
    fs::write(
        dir.join("config.toml"),
        "[user]\nname = \"cli-test\"\nemail = \"cli-test@example.com\"\n",
    )
    .expect("write jj config");
}

/// Create a bare git remote at `<base>/remote.git` seeded with one
/// commit on `main`, and return its path.
fn seed_remote(base: &Path) -> PathBuf {
    let remote = base.join("remote.git");
    let seed = base.join("seed");
    let out = Command::new("git")
        .args(["init", "--bare"])
        .arg(&remote)
        .output()
        .expect("spawn git init --bare");
    assert!(
        out.status.success(),
        "git init --bare failed: {}",
        String::from_utf8_lossy(&out.stderr)
    );
    fs::create_dir_all(&seed).expect("mkdir seed repo");
    jj(&seed, &["git", "init", "--colocate"]);
    fs::write(seed.join("README.md"), "# seed\n").expect("write seed file");
    jj(&seed, &["describe", "@", "-m", "chore: seed"]);
    jj(&seed, &["bookmark", "set", "main", "-r", "@"]);
    jj(
        &seed,
        &[
            "git",
            "remote",
            "add",
            "origin",
            &remote.to_string_lossy(),
        ],
    );
    jj(&seed, &["git", "push", "--bookmark", "main"]);
    remote
}

/// Clone `remote` into `<base>/<name>` (colocated) and return the
/// workdir.
fn clone(base: &Path, remote: &Path, name: &str) -> PathBuf {
    let workdir = base.join(name);
    let out = Command::new("jj")
        .args(["git", "clone", "--colocate"])
        .arg(remote)
        .arg(&workdir)
        .output()
        .expect("spawn jj clone");
    assert!(
        out.status.success(),
        "jj git clone failed: {}",
        String::from_utf8_lossy(&out.stderr)
    );
    workdir
}

/// Two independent clones of one remote: A pushes a commit, then
/// `vc-x1 sync --no-check -R <clone-b>` fast-forwards B's `main`.
#[test]
fn cli_sync_ffs_main_after_peer_push() {
    let fx = CliFixture::new("sync-peer-push");
    write_jj_config(&fx.home);
    let remote = seed_remote(&fx.base);

    // Clone B first so its main@origin is the pre-push head.
    let clone_b = clone(&fx.base, &remote, "clone-b");
    let pre_main = cid(&clone_b, "main");

    // Clone A commits and pushes.
    let clone_a = clone(&fx.base, &remote, "clone-a");
    fs::write(clone_a.join("from-a.txt"), "from clone A\n").expect("write A file");
    jj(&clone_a, &["describe", "@", "-m", "feat: from clone A"]);
    jj(&clone_a, &["bookmark", "set", "main", "-r", "@"]);
    jj(&clone_a, &["git", "push", "--bookmark", "main"]);
    let pushed = cid(&clone_a, "main");
    assert_ne!(pre_main, pushed, "A's push should advance the remote");

    // Sync clone B via the actual binary.
    run_ok(
        fx.cmd()
            .args(["sync", "--no-check", "-R"])
            .arg(&clone_b),
    );

    assert_eq!(
        cid(&clone_b, "main"),
        pushed,
        "clone B's main should ff to A's pushed head"
    );
    assert_eq!(
        cid(&clone_b, "@-"),
        pushed,
        "@ should be repositioned onto the new main"
    );
}

