    fn load_absent_is_none() {
        let repo = unique_base("sync-state-absent");
        fs::create_dir_all(&repo).expect("mkdir fixture repo");
        assert!(load(&repo).expect("load").is_none());
        fs::remove_dir_all(&repo).ok();
    }
}

